// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

module.exports = {
  getTasks(projectId, status) {
    // Simulate fetching tasks from a database
    const tasks = [
      { id: '1', projectId, status: 'todo' },
      { id: '2', projectId, status: 'done' }
    ];

    if (status) {
      return tasks.filter(task => task.status === status);
    }

    return tasks;
  },

  createTask(projectId, taskData) {
    // Simulate creating a new task in the database
    const newTask = {
      id: randomUUID(),
      projectId,
      ...taskData
    };

    // Return the newly created task
    return newTask;
  },

  updateTaskStatus(taskId, status) {
    // Simulate updating a task's status in the database
    const tasks = [
      { id: '1', projectId: 'project1', status: 'todo' },
      { id: '2', projectId: 'project1', status: 'done' }
    ];

    const task = tasks.find(t => t.id === taskId);

    if (task) {
      task.status = status;
      return task;
    }

    return null;
  }
};

// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;

  try {
    const tasks = tasksService.getTasks(projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'An internal error occurred');
  }
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { message } = req.body;

  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Message is required');
  }

  try {
    const newTask = tasksService.createTask(projectId, { message });
    res.status(201).json({ task: newTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'An internal error occurred');
  }
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;

  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }

  try {
    const updatedTask = tasksService.updateTaskStatus(taskId, status);

    if (!updatedTask) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }

    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'An internal error occurred');
  }
});

module.exports = router;

